mapper.select:
select recruitment.id, title, mine_salary, max_salary, start_time, end_time, recruitment.status, province_code, province_name, city_code, city_name, district_code, district_name, detail, username, profile_url, update_time from recruitment,user


    AND status = 1



        AND title LIKE CONCAT('%', #{title}, '%')




        AND city_code = #{cityCode}







                AND DATEDIFF(end_time, start_time) <= 7



                AND DATEDIFF(end_time, start_time) <= 15



                AND DATEDIFF(end_time, start_time) <= 30



                AND DATEDIFF(end_time, start_time) <= 60



                AND DATEDIFF(end_time, start_time) > 60






        AND (

        (#{minSalary} BETWEEN mine_salary AND max_salary)
        OR (#{maxSalary} BETWEEN mine_salary AND max_salary)
        OR (mine_salary BETWEEN #{minSalary} AND #{maxSalary})
        OR (max_salary BETWEEN #{minSalary} AND #{maxSalary})
        )




        AND max_salary >= #{minSalary}


        AND mine_salary <= #{maxSalary}




        AND mine_salary <= #{exactMinSalary}
        AND max_salary >= #{exactMaxSalary}
